export const iconSizes: Record<IconSizes, string> = {
  sm: "12px",
  md: "16px",
  lg: "24px",
};

function Icon(props: IconProps) {
  // TODO: Add a warning when an onClick is passed: "consider using a button with the isIconButton flag instead"
