import { ErrorBasicBuilder, ErrorWriter } from './base'
import { SuggestionObjectValue } from './SuggestionObjectValue'

export class ObjectFieldSuggestion implements ErrorBasicBuilder {
  public isRequired = false
  constructor(
    readonly name: string,
    readonly value: string | SuggestionObjectValue,
  ) {}

  makeRequired() {
    this.isRequired = true
    return this
  }

  write(writer: ErrorWriter): void {
    const {
      colors: { green },
    } = writer.context

    writer.addMarginSymbol(green(this.isRequired ? '+' : '?'))
    writer.write(green(this.name))

    if (!this.isRequired) {
      writer.write(green('?'))
    }

    writer.write(green(`: `))
    if (typeof this.value === 'string') {
      writer.write(green(this.value))
    } else {
      writer.write(this.value)
    }
  }
}

import { getStorybookInfo } from 'storybook/internal/common';
import type { StorybookConfig } from 'storybook/internal/types';

import { cleanPaths } from './sanitize.ts';

const cleanAndSanitizePath = (path: string) => {
  return cleanPaths(path).replace(/.*node_modules[\\/]/, '');
};

export async function getFrameworkInfo(mainConfig: StorybookConfig, configDir: string) {
  const { frameworkPackage, rendererPackage, builderPackage } = await getStorybookInfo(configDir);

  const frameworkOptions =
    typeof mainConfig.framework === 'object' ? mainConfig.framework.options : {};

  return {
    framework: {
      name: frameworkPackage ? cleanAndSanitizePath(frameworkPackage) : undefined,
      options: frameworkOptions,
    },
    builder: builderPackage ? cleanAndSanitizePath(builderPackage) : undefined,
    renderer: rendererPackage ? cleanAndSanitizePath(rendererPackage) : undefined,
  };
}

import { BootstrapState, bootstrap } from '../bin';
import { argPrefix, compress, decompress } from './argv-payload';

const base64ConfigArg = process.argv[2];
if (!base64ConfigArg.startsWith(argPrefix)) throw new Error('unexpected argv');
const base64Payload = base64ConfigArg.slice(argPrefix.length);
const state = decompress(base64Payload) as BootstrapState;

state.isInChildProcess = true;
state.tsNodeScript = __filename;
state.parseArgvResult.argv = process.argv;
state.parseArgvResult.restArgs = process.argv.slice(3);

// Modify and re-compress the payload delivered to subsequent child processes.
// This logic may be refactored into bin.ts by https://github.com/TypeStrong/ts-node/issues/1831
if (state.isCli) {
  const stateForChildren: BootstrapState = {
    ...state,
    isCli: false,
  };
  state.parseArgvResult.argv[2] = `${argPrefix}${compress(stateForChildren)}`;
}

bootstrap(state);

